// Auto-generated Earth elevation & moisture data (145x80 grid)
// Elevation: 0=ocean, 1-79=land(low), 80=plains, 130=highlands, 200=mountains
// Moisture: 0-255 (0=very dry desert, 255=very wet tropical)
export const EARTH_ELEV="";
export const EARTH_MOIST="";
export const EARTH_W=145,EARTH_H=80;

// Decode base64 to Uint8Array
export function decodeEarth(b64) {
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

// Bilinear sample from low-res grid to high-res pixel
export function sampleEarth(data, sw, sh, x, y, tw, th) {
  const fx = (x / tw) * sw, fy = (y / th) * sh;
  const x0 = Math.floor(fx), y0 = Math.floor(fy);
  const x1 = Math.min(sw - 1, x0 + 1), y1 = Math.min(sh - 1, y0 + 1);
  const dx = fx - x0, dy = fy - y0;
  const v00 = data[y0 * sw + (x0 % sw)], v10 = data[y0 * sw + (x1 % sw)];
  const v01 = data[y1 * sw + (x0 % sw)], v11 = data[y1 * sw + (x1 % sw)];
  return v00 * (1-dx) * (1-dy) + v10 * dx * (1-dy) + v01 * (1-dx) * dy + v11 * dx * dy;
}
